module RefModule(
	input clk,
	input reset,
	input up_down,  // 1 for up, 0 for down
	output reg [2:0] count);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (reset) 
			count <= 3'b000;
		else if (up_down)
			count <= count + 1;
		else
			count <= count - 1;
	end

endmodule
